transform_js:
var sorted = rawData.rows.slice().sort(function(a, b) { return b.count - a.count; });
var total = sorted.reduce(function(s, r) { return s + r.count; }, 0);
var cum = 0;
var causes = sorted.map(function(r) { return r.cause; });
var counts = sorted.map(function(r) { return r.count; });
var cumPct = sorted.map(function(r) { cum += r.count; return Math.round(cum / total * 100); });
transformedData = { causes: causes, counts: counts, cumPct: cumPct };

echarts_js:
option = {
  title: { text: 'Defect Analysis (Pareto)', left: 'center' },
  tooltip: { trigger: 'axis' },
  legend: { bottom: '5%' },
  grid: { left: '10%', right: '10%', bottom: '15%' },
  xAxis: { type: 'category', data: transformedData.causes, axisLabel: { rotate: 30 } },
  yAxis: [
    { type: 'value', name: 'Count' },
    { type: 'value', name: 'Cumulative %', max: 100, axisLabel: { formatter: '{value}%' } }
  ],
  series: [
    { name: 'Count', type: 'bar', data: transformedData.counts, itemStyle: { color: '#5470c6' } },
    { name: 'Cumulative %', type: 'line', yAxisIndex: 1, data: transformedData.cumPct, symbol: 'circle', symbolSize: 8, lineStyle: { color: '#ee6666', width: 2 }, itemStyle: { color: '#ee6666' } }
  ]
};
